using Microsoft.AspNetCore.Mvc;
using System.Collections.Generic;
using System.Linq;
using System.Web; // Required for HttpUtility

public class ProductController : Controller
{
    private readonly ApplicationDbContext _context; // Assume you have a DbContext

    public ProductController(ApplicationDbContext context)
    {
        _context = context;
    }

    // GET: /Product/Details/{productId}
    public IActionResult Details(int productId)
    {
        // Fetch product details (if needed)
        // var product = _context.Products.FirstOrDefault(p => p.Id == productId);
        // if (product == null)
        // {
        //     return NotFound();
        // }

        // Fetch reviews for the product
        var reviews = _context.Reviews
                              .Where(r => r.ProductId == productId)
                              .OrderByDescending(r => r.ReviewDate)
                              .ToList();

        // Pass reviews to the view
        var model = new ProductDetailsViewModel
        {
            ProductId = productId,
            ProductName = "Example Product", // Replace with actual product name
            Reviews = reviews
        };

        return View(model);
    }
}

// Model for the review entity (assuming this maps to your database table)
public class Review
{
    public int Id { get; set; }
    public int ProductId { get; set; }
    public string ReviewerName { get; set; }
    public int Rating { get; set; } // e.g., 1-5 stars
    public string Comment { get; set; }
    public System.DateTime ReviewDate { get; set; } = System.DateTime.Now;
}

// ViewModel for the Product Details page
public class ProductDetailsViewModel
{
    public int ProductId { get; set; }
    public string ProductName { get; set; }
    public List<Review> Reviews { get; set; } = new List<Review>();
}

